17	const BASE_PREMIUM: Record<string, number> = {
18	  amulet: 60,
19	  sword: 100,
20	  rune: 25,
21	};
22	
23	const FIRST_INSURANCE_RATE = 0.1;
24	const PROCESSING_FEE = 5;
25	
26	const CURSE_SURCHARGE_RATE = 0.5;
27	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
28	const HIGH_ENCHANTMENT_THRESHOLD = 5;
29	const LOYALTY_DISCOUNT_RATE = 0.2;
30	const LOYALTY_THRESHOLD_YEARS = 2;
31	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
32	
33	function sumOver<T>(xs: T[], f: (x: T) => number): number {
34	  return xs.reduce((total, x) => total + f(x), 0);
35	}
36	
37	// MHPCO rounds quote premiums UP (in the office's favor).
38	function roundUpInFavorOfOffice(amount: number): number {
39	  return Math.ceil(amount);
40	}
41	
42	function itemBasePremium(item: QuoteItem): number {
43	  return BASE_PREMIUM[item.type] ?? 0;
44	}
45	
46	function itemSurcharges(item: QuoteItem): number {
47	  const base = itemBasePremium(item);
48	  const curseSurcharge = item.cursed ? base * CURSE_SURCHARGE_RATE : 0;
49	  const highEnchantmentSurcharge =
50	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
51	      ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE
52	      : 0;
53	  return curseSurcharge + highEnchantmentSurcharge;
54	}
55	
56	function priceQuoteStep(
57	  step: QuoteStep,
58	  yearsWithMHPCO: number,
59	  isFollowUp: boolean,
60	): { premium: number } {
61	  const policyBase = sumOver(step.items, itemBasePremium);
62	  const itemSurchargeTotal = sumOver(step.items, itemSurcharges);
63	  const firstInsurance = policyBase * FIRST_INSURANCE_RATE;
64	  const loyaltyDiscount =
65	    yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS
66	      ? policyBase * LOYALTY_DISCOUNT_RATE
67	      : 0;
68	  const followUpDiscount = isFollowUp
69	    ? policyBase * FOLLOW_UP_DISCOUNT_RATE
70	    : 0;
71	  const premium = roundUpInFavorOfOffice(
72	    policyBase +
73	      itemSurchargeTotal +
74	      firstInsurance -
75	      loyaltyDiscount -
76	      followUpDiscount +
77	      PROCESSING_FEE,
78	  );
79	  return { premium };
80	}
81	
82	export function runScenario(scenario: Scenario): {
83	  results: { premium: number }[];
84	} {
85	  const results = scenario.steps.map((step, index) =>
86	    priceQuoteStep(step, scenario.customer.yearsWithMHPCO, index > 0),
87	  );
88	  return { results };
89	}
